(function() {
  if (!input) return '';
  var html = fetch(input);
  var m = html.match(/<source\s+src="(\/[^"]+get_file[^"]+)"/);
  if (m) {
    return 'https://leslez.com' + m[1];
  }
  m = html.match(/data-preview="[^"]*custom1=([^"&]+)/);
  if (m) {
    return 'https://leslez.com/get_file/1/1/1/1/1?custom=1&f=' + m[1];
  }
  m = html.match(/<source[^>]+src="([^"]+)"/);
  if (m) {
    var src = m[1];
    if (src.indexOf('http') === 0) return src;
    return 'https://leslez.com' + src;
  }
  return '';
})();
